INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('Organisation comptable et gestion de projets', 'Formation sur l’organisation comptable et la gestion de projets pour optimiser la performance et la conformité.', 5, 250000.00, 'entreprise', '2026-04-05', 30, '2026-01-14 12:37:32', '2026-01-14 12:37:32', NULL, E'--- OBJECTIFS ---\n• Comprendre les principes de l’organisation comptable\n• Maîtriser les étapes clés de la gestion de projets\n• Développer des compétences en planification et suivi\n• Optimiser la coordination entre comptabilité et gestion\n• Assurer la conformité et améliorer la performance globale\n\n--- OBJECTIFS DÉTAILLÉS ---\nInitier les participants à l’organisation comptable et à la gestion de projets, leur apprendre à planifier, organiser et piloter efficacement tout en respectant les obligations comptables.\n\n--- PRÉREQUIS ---\nConnaissances de base en comptabilité ou gestion souhaitées.\n\n--- CONTENU ---\nModule 1 : Introduction à l’organisation comptable\nModule 2 : Principes de la gestion de projets\nModule 3 : Planification et organisation\nModule 4 : Suivi et contrôle de l’avancement\nModule 5 : Coordination entre comptabilité et gestion\nModule 6 : Atelier pratique – Élaboration d’un plan comptable et projet\n\n--- NIVEAU ---\nTous niveaux\n\n--- PUBLIC ---\nComptables, gestionnaires de projets, responsables financiers et managers.\n\n--- MÉTHODES ---\nCours interactifs, démonstrations, études de cas, ateliers pratiques et exercices guidés.\n\n--- SUPPORTS ---\nLogiciels de gestion de projets et comptabilité, modèles de planification, supports PDF et slides.\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
